export const name = "repo";
export const version = "0.1.0";
export const description = "";

export function getIdentity() {
  return { name, version, description };
}

export function slugify(input) {
  const s = safeString(input).normalize("NFKD");
  // remove diacritics
  const withoutDiacritics = s.replace(/\p{M}/gu, "");
  // replace non letter/number with hyphen, collapse, trim
  const slug = withoutDiacritics
    .toLowerCase()
    .replace(/[^\p{L}\p{N}]+/gu, "-")
    .replace(/^-+|-+$/g, "")
    .replace(/-+/g, "-");
  return slug;
}

export function truncate(input, maxLength = 20, suffix = "…") {
  const s = safeString(input);
  if (maxLength <= 0) return suffix;
  if (s.length <= maxLength) return s;
  // try to avoid breaking mid-word
  const clipped = s.slice(0, maxLength);
  const lastSpace = clipped.lastIndexOf(" ");
  if (lastSpace > 0) {
    const candidate = clipped.slice(0, lastSpace).trimEnd();
    return candidate + suffix;
  }
  // no space — truncate and ensure space for suffix
  const trimLen = Math.max(0, maxLength - suffix.length);
  return s.slice(0, trimLen) + suffix;
}

export function camelCase(input) {
  const s = safeString(input);
  const parts = s
    .trim()
    .split(/[^\p{L}\p{N}]+/u)
    .filter(Boolean)
    .map((p) => p.toLowerCase());
  if (parts.length === 0) return "";
  return parts[0] + parts.slice(1).map((w) => w.charAt(0).toUpperCase() + w.slice(1)).join("");
}

export function kebabCase(input) {
  const s = safeString(input);
  const parts = s
    .trim()
    .normalize("NFKD")
    .replace(/\p{M}/gu, "")
    .split(/[^\p{L}\p{N}]+/u)
    .filter(Boolean)
    .map((p) => p.toLowerCase());
  return parts.join("-");
}

export function titleCase(input) {
  const s = safeString(input);
  return s
    .trim()
    .split(/\s+/u)
    .filter(Boolean)
    .map((w) => w.charAt(0).toUpperCase() + w.slice(1).toLowerCase())
    .join(" ");
}

export function wordWrap(input, width = 80) {
  const s = safeString(input);
  if (width < 1) return s;
  const words = s.split(/(\s+)/u); // keep spaces to preserve multiple spaces
  const lines = [];
  let line = "";
  for (let i = 0; i < words.length; i++) {
    const token = words[i];
    // token might be space or word
    if (/^\s+$/.test(token)) {
      // spaces: only add a single space when appropriate
      if (line.length === 0) continue; // skip leading spaces
      if ((line + " ").length <= width) {
        line += " ";
      } else {
        lines.push(line);
        line = "";
      }
    } else {
      const word = token;
      if (line.length === 0) {
        // start new line
        if (word.length <= width) {
          line = word;
        } else {
          // single long word — place on its own line unbroken
          lines.push(word);
          line = "";
        }
      } else {
        if ((line + " " + word).length <= width) {
          line = line + " " + word;
        } else {
          lines.push(line);
          if (word.length <= width) {
            line = word;
          } else {
            lines.push(word);
            line = "";
          }
        }
      }
    }
  }
  if (line.length > 0) lines.push(line);
  return lines.join("\n");
}

export function stripHtml(input) {
  let s = safeString(input);
  // remove tags
  s = s.replace(/<[^>]*>/g, "");
  // decode basic entities
  const entities = {
    nbsp: " ",
    lt: "<",
    gt: ">",
    amp: "&",
    quot: '"',
    apos: "'",
  };
  s = s.replace(/&(#?(x)?[0-9a-zA-Z]+);/g, (m, e) => {
    if (e[0] === "#") {
      // numeric
      if (e[1] === "x" || e[1] === "X") {
        return String.fromCodePoint(parseInt(e.slice(2), 16));
      }
      return String.fromCodePoint(parseInt(e.slice(1), 10));
    }
    const key = e.toLowerCase();
    return entities[key] || m;
  });
  return s;
}

export function escapeRegex(input) {
  const s = safeString(input);
  return s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

export function pluralize(input) {
  const s = safeString(input).trim();
  if (s === "") return "";
  const lower = s.toLowerCase();
  // endings: s/x/z/ch/sh -> es
  if (/(s|x|z|ch|sh)$/i.test(lower)) return s + "es";
  // consonant + y -> replace y with ies
  if (/[b-df-hj-np-tv-z]y$/i.test(lower)) return s.slice(0, -1) + "ies";
  // f or fe -> ves
  if (/(?:f|fe)$/i.test(lower)) {
    if (lower.endsWith("fe")) return s.slice(0, -2) + "ves";
    return s.slice(0, -1) + "ves";
  }
  return s + "s";
}

export function levenshtein(aInput, bInput) {
  const a = safeString(aInput);
  const b = safeString(bInput);
  const alen = a.length;
  const blen = b.length;
  if (alen === 0) return blen;
  if (blen === 0) return alen;
  const v0 = new Array(blen + 1);
  const v1 = new Array(blen + 1);
  for (let j = 0; j <= blen; j++) v0[j] = j;
  for (let i = 0; i < alen; i++) {
    v1[0] = i + 1;
    for (let j = 0; j < blen; j++) {
      const cost = a[i] === b[j] ? 0 : 1;
      v1[j + 1] = Math.min(v1[j] + 1, v0[j + 1] + 1, v0[j] + cost);
    }
    for (let j = 0; j <= blen; j++) v0[j] = v1[j];
  }
  return v1[blen];
}
